display_file:
  .space 0x1800
attributes_file:
  .space 0x0300
PRINTER_BUFFER_48:
  .space 0x0100

; =========================
; Standard System Variables
; =========================
; These occupy addresses KSTATE-0x5cb5.
;

sysvars_48k:

KSTATE:
  .space   4                                      ;  IY-0x3a   Used in reading the keyboard.
KSTATE_04:
  .space   4                                      ;  IY-0x36   Used in reading the keyboard.
LASTK:
  .space   1                                      ;  IY-0x32   Stores newly pressed key.
REPDEL:
  .space   1                                      ;  IY-0x31   Time (in 50ths of a second) that a key must be held down before it repeats. This starts off at 35.
REPPER:
  .space   1                                      ;  IY-0x30   Delay (in 50ths of a second) between successive repeats of a key held down - initially 5.
DEFADD:
  .space   1                                      ;  IY-0x2f   Address of arguments of user defined function (if one is being evaluated), otherwise 0 (low).
DEFADD_hi:
  .space   1                                      ;  IY-0x2e   Address of arguments of user defined function (if one is being evaluated), otherwise 0 (high).
K_DATA:
  .space   1                                      ;  IY-0x2d   Stores second byte of colour controls entered from keyboard.
TVDATA:
  .space   1                                      ;  IY-0x2c   Stores bytes of colour, AT and TAB controls going to TV (low).
TVDATA_hi:
  .space   1                                      ;  IY-0x2b   Stores bytes of colour, AT and TAB controls going to TV (high).
STRMS:                                            ;  IY-0x2a   Addresses of channels attached to streams.
STRM_FD:
  .space   2                                      ;  IY-0x2a   Stream -3
STRM_FE:
  .space   2                                      ;  IY-0x28   Stream -2
STRM_FF:
  .space   2                                      ;  IY-0x26   Stream -1
STRM_00:
  .space   2                                      ;  IY-0x24   Stream  0
STRM_01:
  .space   2                                      ;  IY-0x22   Stream  1
STRM_02:
  .space   2                                      ;  IY-0x20   Stream  2
STRM_03:
  .space   2                                      ;  IY-0x1e   Stream  3
STRM_04:
  .space   2                                      ;  IY-0x1c   Stream  4
STRM_05:
  .space   2                                      ;  IY-0x1a   Stream  5
STRM_06:
  .space   2                                      ;  IY-0x18   Stream  6
STRM_07:
  .space   2                                      ;  IY-0x16   Stream  7
STRM_08:
  .space   2                                      ;  IY-0x14   Stream  8
STRM_09:
  .space   2                                      ;  IY-0x12   Stream  9
STRM_0a:
  .space   2                                      ;  IY-0x10   Stream 10
STRM_0b:
  .space   2                                      ;  IY-0x0e   Stream 11
STRM_0c:
  .space   2                                      ;  IY-0x0c   Stream 12
STRM_0d:
  .space   2                                      ;  IY-0x0a   Stream 13
STRM_0e:
  .space   2                                      ;  IY-0x08   Stream 14
STRM_0f:
  .space   2                                      ;  IY-0x06   Stream 15
CHARS:
  .space   2                                      ;  IY-0x04   256 less than address of character set, which starts with ' ' and carries on to '(c)'.
RASP:
  .space   1                                      ;  IY-0x02   Length of warning buzz.
PIP:
  .space   1                                      ;  IY-0x01   Length of keyboard click.
C_IY:                                             ;  IY+0x00   Frozen (constant) value that IY register retains throughout ROM routines
ERR_NR:
  .space   1                                      ;  IY+0x00   1 less than the report code. Starts off at 255 (for -1) so 'PEEK 23610' gives 255.
FLAGS:
  .space   1                                      ;  IY+0x01   Various flags to control the BASIC system:
                                                  ;                 Bit 0: 1=Suppress leading space.
                                                  ;                 Bit 1: 1=Using printer, 0=Using screen.
                                                  ;                 Bit 2: 1=Print in L-Mode, 0=Print in K-Mode.
                                                  ;                 Bit 3: 1=L-Mode, 0=K-Mode.
                                                  ;                 Bit 4: 1=128K Mode, 0=48K Mode. [Always 0 on 48K Spectrum]
                                                  ;                 Bit 5: 1=New key press code available in LAST_K.
                                                  ;                 Bit 6: 1=Numeric variable, 0=String variable.
                                                  ;                 Bit 7: 1=Line execution, 0=Syntax checking.
TV_FLAG:
  .space   1                                      ;  IY+0x02   Flags associated with the TV:
                                                  ;                 Bit 0  : 1=Using lower editing area, 0=Using main screen.
                                                  ;                 Bit 1-2: Not used (always 0).
                                                  ;                 Bit 3  : 1=Mode might have changed.
                                                  ;                 Bit 4  : 1=Automatic listing in main screen, 0=Ordinary listing in main screen.
                                                  ;                 Bit 5  : 1=Lower screen requires clearing after a key press.
                                                  ;                 Bit 6  : 1=Tape Loader option selected (set but never tested). [Always 0 on 48K Spectrum]
                                                  ;                 Bit 7  : Not used (always 0).
ERR_SP:
  .space   2                                      ;  IY+0x03   Address of item on machine stack to be used as error return.
LISTSP:
  .space   2                                      ;  IY+0x05   Address of return address from automatic listing.
MODE:
  .space   1                                      ;  IY+0x07   Specifies cursor type:
                                                  ;                 0x00='L' or 'C'.
                                                  ;                 0x01='E'.
                                                  ;                 0x02='G'.
                                                  ;                 0x04='K'.
NEWPPC:
  .space   2                                      ;  IY+0x08   Line to be jumped to.
NSPPC:
  .space   1                                      ;  IY+0x0a   Statement number in line to be jumped to.
PPC:
  .space   2                                      ;  IY+0x0b   Line number of statement currently being executed.
SUBPPC:
  .space   1                                      ;  IY+0x0d   Number within line of statement currently being executed.
BORDCR:
  .space   1                                      ;  IY+0x0e   Border colour multiplied by 8; also contains the attributes normally used for the lower half
                                                  ;               of the screen.
E_PPC:
  .space   1                                      ;  IY+0x0f   Number of current line (with program cursor) (low).
E_PPC_hi:
  .space   1                                      ;  IY+0x10   Number of current line (with program cursor) (high).
VARS:
  .space   2                                      ;  IY+0x11   Address of variables.
DEST:
  .space   2                                      ;  IY+0x13   Address of variable in assignment.
CHANS:
  .space   2                                      ;  IY+0x15   Address of channel data.
CURCHL:
  .space   2                                      ;  IY+0x17   Address of information currently being used for input and output.
PROG:
  .space   2                                      ;  IY+0x19   Address of BASIC program.
NXTLIN:
  .space   2                                      ;  IY+0x1b   Address of next line in program.
DATADD:
  .space   2                                      ;  IY+0x1d   Address of terminator of last DATA item.
E_LINE:
  .space   2                                      ;  IY+0x1f   Address of command being typed in.
K_CUR:
  .space   1                                      ;  IY+0x21   Address of cursor (low byte).
K_CUR_hi:
  .space   1                                      ;  IY+0x22   Address of cursor (high byte).
CH_ADD:
  .space   2                                      ;  IY+0x23   Address of the next character to be interpreted - the character after the argument of PEEK,
                                                  ;               or the NEWLINE at the end of a POKE statement.
X_PTR:
  .space   1                                      ;  IY+0x25   Address of the character after the '?' marker (low byte).
X_PTR_hi:
  .space   1                                      ;  IY+0x26   Address of the character after the '?' marker (high byte).
WORKSP:
  .space   2                                      ;  IY+0x27   Address of temporary work space.
STKBOT:
  .space   2                                      ;  IY+0x29   Address of bottom of calculator stack.
STKEND:
  .space   1                                      ;  IY+0x2b   Address of start of spare space (low).
STKEND_hi:
  .space   1                                      ;  IY+0x2c   Address of start of spare space (high).
BREG:
  .space   1                                      ;  IY+0x2d   Calculator's B register.
MEM:
  .space   2                                      ;  IY+0x2e   Address of area used for calculator's memory (usually MEMBOT, but not always).
FLAGS2:
  .space   1                                      ;  IY+0x30   Flags:
                                                  ;                 Bit 0  : 1=Screen requires clearing.
                                                  ;                 Bit 1  : 1=Printer buffer contains data.
                                                  ;                 Bit 2  : 1=In quotes.
                                                  ;                 Bit 3  : 1=CAPS LOCK on.
                                                  ;                 Bit 4  : 1=Using channel 'K'.
                                                  ;                 Bit 5-7: Not used (always 0).
DF_SZ:
  .space   1                                      ;  IY+0x31   The number of lines (including one blank line) in the lower part of the screen.
S_TOP:
  .space   2                                      ;  IY+0x32   The number of the top program line in automatic listings.
OLDPPC:
  .space   2                                      ;  IY+0x34   Line number to which CONTINUE jumps.
OSPPC:
  .space   1                                      ;  IY+0x36   Number within line of statement to which CONTINUE jumps.
FLAGX:
  .space   1                                      ;  IY+0x37   Flags:
                                                  ;                 Bit 0  : 1=Simple string complete so delete old copy.
                                                  ;                 Bit 1  : 1=Indicates new variable, 0=Variable exists.
                                                  ;                 Bit 2-4: Not used (always 0).
                                                  ;                 Bit 5  : 1=INPUT mode.
                                                  ;                 Bit 6  : 1=Numeric variable, 0=String variable. Holds nature of existing variable.
                                                  ;                 Bit 7  : 1=Using INPUT LINE.
STRLEN:
  .space   2                                      ;  IY+0x38   Length of string type destination in assignment.
T_ADDR:
  .space   2                                      ;  IY+0x3a   Address of next item in syntax table.
SEED:
  .space   2                                      ;  IY+0x3c   The seed for RND. Set by RANDOMIZE.
FRAMES:
  .space   2                                      ;  IY+0x3e   3 byte (least significant byte first), frame counter incremented every 20ms.
FRAMES_hi:
  .space   1                                      ;  IY+0x40   MSB of FRAMES
UDG:
  .space   2                                      ;  IY+0x41   Address of first user-defined graphic. Can be changed to save space by having fewer
                                                  ;               user-defined characters.
COORDS_X:
  .space   1                                      ;  IY+0x43   X-coordinate of last point plotted.
COORDS_Y:
  .space   1                                      ;  IY+0x44   Y-coordinate of last point plotted.
P_POSN_X:
  .space   1                                      ;  IY+0x45   33-column number of printer position.
PR_CC:
  .space   2                                      ;  IY+0x46   Full address of next position for LPRINT to print at (in ZX Printer buffer).
                                                  ;               Legal values PRINTER_BUFFER_48 - 0x5b1f. [Not used in 128K mode]
ECHO_E_X:
  .space   1                                      ;  IY+0x48   33-column number of end of input buffer.
ECHO_E_Y:
  .space   1                                      ;  IY+0x49   24-line number (in lower half) of end of input buffer.
DF_CC:
  .space   2                                      ;  IY+0x4a   Address in display file of PRINT position.
DF_CC_L:
  .space   2                                      ;  IY+0x4c   Like DF CC for lower part of screen.
S_POSN_X:
  .space   1                                      ;  IY+0x4e   33-column number for PRINT position.
S_POSN_Y:
  .space   1                                      ;  IY+0x4f   24-line number for PRINT position.
S_POSN_X_L:
  .space   1                                      ;  IY+0x50   Like S_POSN_X for lower part.
S_POSN_Y_L:
  .space   1                                      ;  IY+0x51   Like S_POSN_Y for lower part.
SCR_CT:
  .space   1                                      ;  IY+0x52   Counts scrolls - it is always 1 more than the number of scrolls that will be done before
                                                  ;               stopping with 'scroll?'.
ATTR_P:
  .space   1                                      ;  IY+0x53   Permanent current colours, etc, as set up by colour statements.
MASK_P:
  .space   1                                      ;  IY+0x54   Used for transparent colours, etc. Any bit that is 1 shows that the corresponding attribute
                                                  ;               bit is taken not from ATTR_P, but from what is already on the screen.
ATTR_T:
  .space   1                                      ;  IY+0x55   Temporary current colours (as set up by colour items).
MASK_T:
  .space   1                                      ;  IY+0x56   Like MASK_P, but temporary.
P_FLAG:
  .space   1                                      ;  IY+0x57   Flags:
                                                  ;                 Bit 0: (temp) 1=OVER 1, 0=OVER 0.
                                                  ;                 Bit 1: (perm) 1=OVER 1, 0=OVER 0.
                                                  ;                 Bit 2: (temp) 1=INVERSE 1, 0=INVERSE 0.
                                                  ;                 Bit 3: (perm) 1=INVERSE 1, 0=INVERSE 0.
                                                  ;                 Bit 4: (temp) 1=Using INK 9.
                                                  ;                 Bit 5: (perm) 1=Using INK 9.
                                                  ;                 Bit 6: (temp) 1=Using PAPER 9.
                                                  ;                 Bit 7: (perm) 1=Using PAPER 9.
MEMBOT:
  .space   1                                      ;  IY+0x58   30 bytes of calculator's memory - used to store numbers that cannot conveniently be put on the
                                                  ;               calculator stack.
MEMBOT_01:
  .space   1                                      ;  IY+0x59
MEMBOT_02:
  .space   1                                      ;  IY+0x5a
MEMBOT_03:
  .space   1                                      ;  IY+0x5b
MEMBOT_04:
