; ----------------
; THE 'KEY' TABLES
; ----------------
; These six look-up tables are used by the keyboard reading routine
; to decode the key values.

; The first table contains the maps for the 39 keys of the standard
; 40-key Spectrum keyboard. The remaining key [SHIFT 0x27] is read directly.
; The keys consist of the 26 upper-case alphabetic characters, the 10 digit
; keys and the space, ENTER and symbol shift key.
; Unshifted alphabetic keys have 0x20 added to the value.
; The keywords for the main alphabetic keys are obtained by adding 0xa5 to
; the values obtained from this table.

main_keys:
  .byte    0x42                                   ; B
  .byte    0x48                                   ; H
  .byte    0x59                                   ; Y
  .byte    0x36                                   ; 6
  .byte    0x35                                   ; 5
  .byte    0x54                                   ; T
  .byte    0x47                                   ; G
  .byte    0x56                                   ; V
  .byte    0x4e                                   ; N
  .byte    0x4a                                   ; J
  .byte    0x55                                   ; U
  .byte    0x37                                   ; 7
  .byte    0x34                                   ; 4
  .byte    0x52                                   ; R
  .byte    0x46                                   ; F
  .byte    0x43                                   ; C
  .byte    0x4d                                   ; M
  .byte    0x4b                                   ; K
  .byte    0x49                                   ; I
  .byte    0x38                                   ; 8
  .byte    0x33                                   ; 3
  .byte    0x45                                   ; E
  .byte    0x44                                   ; D
  .byte    0x58                                   ; X
  .byte    0x0e                                   ; SYMBOL SHIFT
  .byte    0x4c                                   ; L
  .byte    0x4f                                   ; O
  .byte    0x39                                   ; 9
  .byte    0x32                                   ; 2
  .byte    0x57                                   ; W
  .byte    0x53                                   ; S
  .byte    0x5a                                   ; Z
