p_random:
  .byte    0x03                                   ; Class-03 - A numeric expression may follow
                                                  ; else default to zero.
  .word    randomize                              ; Address: randomize; Address: RANDOMIZE

p_cont:
  .byte    0x00                                   ; Class-00 - No further operands.
  .word    continue                               ; Address: continue; Address: CONTINUE

p_clear:
  .byte    0x03                                   ; Class-03 - A numeric expression may follow
                                                  ; else default to zero.
  .word    clear                                  ; Address: clear; Address: CLEAR

p_cls:
  .byte    0x00                                   ; Class-00 - No further operands.
  .word    cls                                    ; Address: cls; Address: CLS

p_plot:
  .byte    0x09                                   ; Class-09 - Two comma-separated numeric
                                                  ; expressions required with optional colour
                                                  ; items.
  .byte    0x00                                   ; Class-00 - No further operands.
  .word    plot                                   ; Address: plot; Address: PLOT

p_pause:
  .byte    0x06                                   ; Class-06 - A numeric expression must follow.
  .byte    0x00                                   ; Class-00 - No further operands.
  .word    pause                                  ; Address: pause; Address: PAUSE

p_read:
  .byte    0x05                                   ; Class-05 - Variable syntax checked entirely
                                                  ; by routine.
  .word    read                                   ; Address: read; Address: READ

p_data:
  .byte    0x05                                   ; Class-05 - Variable syntax checked entirely
                                                  ; by routine.
  .word    data                                   ; Address: data; Address: DATA

p_restore:
  .byte    0x03                                   ; Class-03 - A numeric expression may follow
                                                  ; else default to zero.
  .word    restore                                ; Address: restore; Address: RESTORE

p_draw:
  .byte    0x09                                   ; Class-09 - Two comma-separated numeric
                                                  ; expressions required with optional colour
                                                  ; items.
  .byte    0x05                                   ; Class-05 - Variable syntax checked
                                                  ; by routine.
  .word    draw                                   ; Address: draw; Address: DRAW

p_copy:
  .byte    0x00                                   ; Class-00 - No further operands.
  .word    copy                                   ; Address: copy; Address: COPY

p_lprint:
  .byte    0x05                                   ; Class-05 - Variable syntax checked entirely
                                                  ; by routine.
  .word    lprint                                 ; Address: lprint; Address: LPRINT

p_llist:
  .byte    0x05                                   ; Class-05 - Variable syntax checked entirely
                                                  ; by routine.
  .word    llist                                  ; Address: llist; Address: LLIST

p_save:
  .byte    0x0b                                   ; Class-0B - Offset address converted to tape
                                                  ; command.

p_load:
  .byte    0x0b                                   ; Class-0B - Offset address converted to tape
                                                  ; command.

p_verify:
  .byte    0x0b                                   ; Class-0B - Offset address converted to tape
                                                  ; command.

p_merge:
  .byte    0x0b                                   ; Class-0B - Offset address converted to tape
                                                  ; command.

p_beep:
