                                                  ; colour code.

p_paper:
  .byte    0x07                                   ; Class-07 - Offset address is converted to
                                                  ; colour code.

p_flash:
  .byte    0x07                                   ; Class-07 - Offset address is converted to
                                                  ; colour code.

p_bright:
  .byte    0x07                                   ; Class-07 - Offset address is converted to
                                                  ; colour code.

p_inverse:
  .byte    0x07                                   ; Class-07 - Offset address is converted to
                                                  ; colour code.

p_over:
  .byte    0x07                                   ; Class-07 - Offset address is converted to
                                                  ; colour code.

p_out:
  .byte    0x08                                   ; Class-08 - Two comma-separated numeric
                                                  ; expressions required.
