p_open:
  .byte    0x06                                   ; Class-06 - A numeric expression must follow.
  .byte    0x2c                                   ; Separator:  ','          see Footnote *
  .byte    0x0a                                   ; Class-0A - A string expression must follow.
  .byte    0x00                                   ; Class-00 - No further operands.
  .word    open                                   ; Address: open; Address: OPEN

p_close:
