p_format:
  .byte    0x0a                                   ; Class-0A - A string expression must follow.
  .byte    0x00                                   ; Class-00 - No further operands.
  .word    cat_etc                                ; Address: cat_etc; Address: CAT-ETC

p_move:
  .byte    0x0a                                   ; Class-0A - A string expression must follow.
  .byte    0x2c                                   ; Separator:  ','
  .byte    0x0a                                   ; Class-0A - A string expression must follow.
  .byte    0x00                                   ; Class-00 - No further operands.
  .word    cat_etc                                ; Address: cat_etc; Address: CAT-ETC

p_erase:
